from collections import defaultdict

def solve(nums: List[int], k: int) -> int:
    def dfs(index, val):
        if index == len(nums):
            return 1 if val == k else 0
        res = 0
        for op in [1, -1, 0]:  # 1: multiply, -1: divide, 0: keep
            if op == 1:
                new_val = val * nums[index]
            elif op == -1:
                new_val = val / nums[index]
